// bench_futamura.mjs — measure the Futamura-projection headroom on fib/tak.
//
// Compares per benchmark:
//   lisp_big.wasm                tree-walker on the full Lisp source
//   bytecode_gc.wasm             bytecode VM (mark-sweep GC) on the same source
//   residual_*_gen.wasm          generated by prototype/futamura/specialize.c
//                                from the .lisp source; tagged-rep PE residual
//   residual_*_untagged.wasm     hand-written reference (rep-specialized i32),
//                                what a PE with type-flow analysis would emit
//
// The residuals take just the bare integer arguments (the source was
// specialized away); engines get the full Lisp program. All go through V8 +
// the same eval_source ABI; we time best-of-25.
//
// If the *_gen wasm files are missing, run `bash prototype/futamura/build.sh`.

import fs from 'fs';
import { spawnSync } from 'child_process';
import { fileURLToPath } from 'url';
import path from 'path';

// Self-bootstrap: if any residual is missing, run the futamura build script.
const ROOT = path.dirname(path.dirname(fileURLToPath(import.meta.url)));
const NEEDED = ['residual_fib_gen.wasm', 'residual_tak_gen.wasm',
                'residual_closures_demo_gen.wasm',
                'residual_closures_v2_demo_gen.wasm',
                'residual_closures_named_demo_gen.wasm',
                'residual_nrev_demo_gen.wasm',
                'residual_fib_untagged.wasm', 'residual_tak_untagged.wasm'];
const missing = NEEDED.filter(f => !fs.existsSync(path.join(ROOT, f)));
if (missing.length) {
  console.log('building futamura residuals (missing: ' + missing.join(', ') + ')');
  const r = spawnSync('bash', [path.join(ROOT, 'prototype/futamura/build.sh')], { stdio: 'inherit' });
  if (r.status !== 0) { console.error('build.sh failed'); process.exit(1); }
}

const FIB_SRC = `(begin
  (define fib (lambda (n) (if (< n 2) n (+ (fib (- n 1)) (fib (- n 2))))))
  (fib 24))`;
const FIB_N = '24';
const FIB_EXPECTED = '46368';

const TAK_SRC = `(begin
  (define tak (lambda (x y z)
    (if (< y x)
        (tak (tak (- x 1) y z) (tak (- y 1) z x) (tak (- z 1) x y))
        z)))
  (tak 18 12 6))`;
const TAK_IN = '18 12 6';
const TAK_EXPECTED = '7';

// Closures-v1 demo: validates `let` + inline-lambda specialization. The body
// of `work` reduces to `(+ n 15)` at spec time after the let bindings (k=5,
// m=10) and the inline lambda application both substitute through. `loop`
// iterates work 1000 times.
const CLOSURES_SRC = `(begin
  (define (work n) (let ((k 5) (m 10)) ((lambda (x) (+ x (+ k m))) n)))
  (define (loop i acc) (if (= i 0) acc (loop (- i 1) (+ acc (work i)))))
  (loop 1000 0))`;
const CLOSURES_IN = '1000 0';
const CLOSURES_EXPECTED = '515500';

// Closures-v2: canonical Futamura-on-closures pattern. (make-adder 5) is
// evaluated at spec time to a closure value capturing n=5; the closure is
// then beta-reduced at the call site `((make-adder 5) m)`, producing a
// residual `work` body equivalent to (+ m 5). make-adder itself never
// reaches the runtime — the specializer skips emitting it.
const CLOSURES_V2_SRC = `(begin
  (define (make-adder n) (lambda (x) (+ x n)))
  (define (work m) ((make-adder 5) m))
  (define (loop i acc) (if (= i 0) acc (loop (- i 1) (+ acc (work i)))))
  (loop 1000 0))`;
const CLOSURES_V2_IN = '1000 0';
const CLOSURES_V2_EXPECTED = '505500';

// Closures-v2-deep: same semantics as closures_v2 but with the closure named
// at top level via `(define add5 (make-adder 5))`. The residual wasm should
// be byte-identical to closures_v2 — this row exists to make the equivalence
// visible in the bench output.
const CLOSURES_NAMED_SRC = `(begin
  (define (make-adder n) (lambda (x) (+ x n)))
  (define add5 (make-adder 5))
  (define (work m) (add5 m))
  (define (loop i acc) (if (= i 0) acc (loop (- i 1) (+ acc (work i)))))
  (loop 1000 0))`;
const CLOSURES_NAMED_IN = '1000 0';
const CLOSURES_NAMED_EXPECTED = '505500';

const NREV_SRC = `(begin
  (define (iota n) (if (= n 0) '() (cons n (iota (- n 1)))))
  (define (append a b) (if (null? a) b (cons (car a) (append (cdr a) b))))
  (define (nrev l) (if (null? l) '() (append (nrev (cdr l)) (cons (car l) '()))))
  (define (lsum l) (if (null? l) 0 (+ (car l) (lsum (cdr l)))))
  (define (work) (lsum (nrev (iota 50))))
  (work))`;
const NREV_IN = '';
const NREV_EXPECTED = '1275';

async function load(file) {
  const bytes = fs.readFileSync(new URL('../' + file, import.meta.url));
  const { instance } = await WebAssembly.instantiate(bytes, {});
  const e = instance.exports;
  const mem = new Uint8Array(e.memory.buffer);
  const enc = new TextEncoder(), dec = new TextDecoder();
  return {
    run(src) {
      const bytes = enc.encode(src);
      mem.set(bytes, e.input_ptr());
      const n = e.eval_source(bytes.length);
      return dec.decode(mem.subarray(e.output_ptr(), e.output_ptr() + n));
    }
  };
}

function bestOf(fn, reps = 25) {
  let lo = Infinity, res;
  for (let i = 0; i < reps; i++) {
    const t = process.hrtime.bigint();
    res = fn();
    const d = Number(process.hrtime.bigint() - t) / 1e6;
    if (d < lo) lo = d;
  }
  return { ms: lo, res };
}

const BENCHMARKS = [
  {
    name: 'fib(24)',
    expected: FIB_EXPECTED,
    rows: [
      ['tree-walker (lisp)',          'lisp_big.wasm',              FIB_SRC],
      ['bytecode_gc',                 'bytecode_gc.wasm',           FIB_SRC],
      ['residual (specialize → gen)', 'residual_fib_gen.wasm',      FIB_N],
      ['residual: untagged (i32)',    'residual_fib_untagged.wasm', FIB_N],
    ],
  },
  {
    name: 'tak(18,12,6)',
    expected: TAK_EXPECTED,
    rows: [
      ['tree-walker (lisp)',          'lisp_big.wasm',              TAK_SRC],
      ['bytecode_gc',                 'bytecode_gc.wasm',           TAK_SRC],
      ['residual (specialize → gen)', 'residual_tak_gen.wasm',      TAK_IN],
      ['residual: untagged (i32)',    'residual_tak_untagged.wasm', TAK_IN],
    ],
  },
  {
    name: 'closures-loop(1000)',
    expected: CLOSURES_EXPECTED,
    rows: [
      ['tree-walker (lisp)',          'lisp_big.wasm',                       CLOSURES_SRC],
      ['bytecode_gc',                 'bytecode_gc.wasm',                    CLOSURES_SRC],
      ['residual (specialize → gen)', 'residual_closures_demo_gen.wasm',     CLOSURES_IN],
    ],
  },
  {
    name: 'make-adder(1000)',
    expected: CLOSURES_V2_EXPECTED,
    rows: [
      ['tree-walker (lisp)',          'lisp_big.wasm',                       CLOSURES_V2_SRC],
      ['bytecode_gc',                 'bytecode_gc.wasm',                    CLOSURES_V2_SRC],
      ['residual (specialize → gen)', 'residual_closures_v2_demo_gen.wasm',  CLOSURES_V2_IN],
    ],
  },
  {
    name: 'named-add5(1000)',
    expected: CLOSURES_NAMED_EXPECTED,
    rows: [
      ['tree-walker (lisp)',          'lisp_big.wasm',                          CLOSURES_NAMED_SRC],
      ['bytecode_gc',                 'bytecode_gc.wasm',                       CLOSURES_NAMED_SRC],
      ['residual (specialize → gen)', 'residual_closures_named_demo_gen.wasm',  CLOSURES_NAMED_IN],
    ],
  },
  {
    name: 'nrev-50',
    expected: NREV_EXPECTED,
    rows: [
      ['tree-walker (lisp)',          'lisp_big.wasm',                 NREV_SRC],
      ['bytecode_gc',                 'bytecode_gc.wasm',              NREV_SRC],
      ['residual (specialize → gen)', 'residual_nrev_demo_gen.wasm',   NREV_IN],
    ],
  },
];

const main = async () => {
  for (const bench of BENCHMARKS) {
    const runs = [];
    for (const [name, file, src] of bench.rows) {
      const eng = await load(file);
      for (let i = 0; i < 5; i++) eng.run(src);  // warm-up
      const r = bestOf(() => eng.run(src));
      runs.push({ name, file, ms: r.ms, res: r.res });
    }

    console.log(`\nbenchmark: ${bench.name} — best-of-25, wasm-on-V8\n`);
    const w = 28;
    console.log('engine'.padEnd(w) + 'wasm'.padStart(30) + 'ms'.padStart(10) + '  result   vs tree-walker');
    console.log('-'.repeat(w + 30 + 10 + 26));
    const tw = runs[0].ms;
    for (const r of runs) {
      const ok = r.res === bench.expected ? '✓' : `⚠ got ${r.res}`;
      const ratio = (tw / r.ms).toFixed(2) + 'x';
      console.log(
        r.name.padEnd(w) +
        r.file.padStart(30) +
        r.ms.toFixed(3).padStart(10) +
        '   ' + bench.expected.padEnd(6) + ratio.padStart(8) + '  ' + ok
      );
    }

    console.log('\nratios:');
    const m = Object.fromEntries(runs.map(r => [r.name, r.ms]));
    const tw_   = m['tree-walker (lisp)'];
    const bcgc  = m['bytecode_gc'];
    const gen   = m['residual (specialize → gen)'];
    const i32_  = m['residual: untagged (i32)'];
    if (tw_ && bcgc)       console.log(`  tree-walker / bytecode_gc          = ${(tw_  / bcgc).toFixed(2)}x`);
    if (bcgc && gen)       console.log(`  bytecode_gc / residual (gen)       = ${(bcgc / gen).toFixed(2)}x`);
    if (gen  && i32_)      console.log(`  residual gen / residual i32        = ${(gen  / i32_).toFixed(2)}x`);
    if (tw_  && gen)       console.log(`  tree-walker / residual (gen)       = ${(tw_  / gen).toFixed(2)}x`);
    if (tw_  && i32_)      console.log(`  tree-walker / residual (i32)       = ${(tw_  / i32_).toFixed(2)}x`);
  }
};

main().catch(e => { console.error(e); process.exit(1); });
